define(["jquery"],function($){return{getScript:function(id_key,type,minLines){return;$.getScript("https://ajaxorg.github.io/ace-builds/src-min-noconflict/ace.js",function(){var html=`
                    <div id="editor_${id_key}_area">
                        <div id='editor_${id_key}' style='width:100%;height:300px;'></div>
                    </div>`;var inputhtml=$(`#${id_key}`).after(html).val();$(`#editor_${id_key}`).html(inputhtml);console.log([id_key,type,minLines]);var editor=ace.edit(`editor_${id_key}`);return;editor.session.on("change",function(delta){$(`#${id_key}`).val(editor.getValue());var numLines=editor.getSession().getDocument().getLength();var newHeight=editor.renderer.lineHeight*numLines;if(newHeight<100){newHeight=100}$(`#editor_${id_key}`).height(newHeight);editor.resize()});editor.session.on("changeAnnotation",function(){var annotations=editor.session.getAnnotations()||[],i=len=annotations.length;while(i--){if(/doctype first\. Expected/.test(annotations[i].text)){annotations.splice(i,1)}}if(len>annotations.length){editor.session.setAnnotations(annotations)}});if(!minLines){minLines=6}editor.setOptions({minLines:minLines});window[`editor_${id_key}`]=editor})}}});